import{_ as t,o as s,c as e,ag as n}from"./chunks/framework.6MCaaFDc.js";const b=JSON.parse('{"title":"Number Conversion — Quick Reference","description":"","frontmatter":{},"headers":[],"relativePath":"quick-study/number-conversion.md","filePath":"quick-study/number-conversion.md"}'),r={name:"quick-study/number-conversion.md"};function d(i,a,l,p,o,c){return s(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="number-conversion-—-quick-reference" tabindex="-1">Number Conversion — Quick Reference <a class="header-anchor" href="#number-conversion-—-quick-reference" aria-label="Permalink to &quot;Number Conversion — Quick Reference&quot;">​</a></h1><p>Fast-scan guide for binary, decimal, and hexadecimal conversions. Steps only — no prose.</p><hr><h2 id="decimal-→-binary" tabindex="-1">Decimal → Binary <a class="header-anchor" href="#decimal-→-binary" aria-label="Permalink to &quot;Decimal → Binary&quot;">​</a></h2><p><strong>Repeated division by 2. Read remainders bottom to top.</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>45 ÷ 2 = 22 r 1</span></span>
<span class="line"><span>22 ÷ 2 = 11 r 0</span></span>
<span class="line"><span>11 ÷ 2 =  5 r 1</span></span>
<span class="line"><span> 5 ÷ 2 =  2 r 1</span></span>
<span class="line"><span> 2 ÷ 2 =  1 r 0</span></span>
<span class="line"><span> 1 ÷ 2 =  0 r 1  ← start reading here</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Result: 101101  (read bottom to top)</span></span>
<span class="line"><span>Verify: 32+8+4+1 = 45 ✓</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><hr><h2 id="binary-→-decimal" tabindex="-1">Binary → Decimal <a class="header-anchor" href="#binary-→-decimal" aria-label="Permalink to &quot;Binary → Decimal&quot;">​</a></h2><p><strong>Write place values above. Add where bit = 1.</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Place: 128  64  32  16   8   4   2   1</span></span>
<span class="line"><span>Bits:    1   0   1   1   0   1   0   1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>128 + 32 + 16 + 4 + 1 = 181</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><hr><h2 id="decimal-→-hex" tabindex="-1">Decimal → Hex <a class="header-anchor" href="#decimal-→-hex" aria-label="Permalink to &quot;Decimal → Hex&quot;">​</a></h2><p><strong>Repeated division by 16. Convert remainders &gt; 9 to A–F. Read bottom to top.</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>255 ÷ 16 = 15 r 15 (F)</span></span>
<span class="line"><span> 15 ÷ 16 =  0 r 15 (F)  ← start reading here</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Result: FF</span></span>
<span class="line"><span>Verify: 15×16 + 15 = 255 ✓</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="hex-→-decimal" tabindex="-1">Hex → Decimal <a class="header-anchor" href="#hex-→-decimal" aria-label="Permalink to &quot;Hex → Decimal&quot;">​</a></h2><p><strong>Multiply each digit by its place value (power of 16). Add.</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2B16:</span></span>
<span class="line"><span>B = 11 →  11 × 16 = 176</span></span>
<span class="line"><span>2      →   2 ×  1 =   2</span></span>
<span class="line"><span>               Total = 178</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Place values: 16⁰=1, 16¹=16, 16²=256, 16³=4096</p><hr><h2 id="binary-↔-hex-shortcut" tabindex="-1">Binary ↔ Hex Shortcut <a class="header-anchor" href="#binary-↔-hex-shortcut" aria-label="Permalink to &quot;Binary ↔ Hex Shortcut&quot;">​</a></h2><p><strong>1 hex digit = exactly 4 binary bits</strong></p><h3 id="binary-→-hex" tabindex="-1">Binary → Hex <a class="header-anchor" href="#binary-→-hex" aria-label="Permalink to &quot;Binary → Hex&quot;">​</a></h3><p>Group 4 bits from right. Convert each group.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1101 0110</span></span>
<span class="line"><span>  D    6   →  D6</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="hex-→-binary" tabindex="-1">Hex → Binary <a class="header-anchor" href="#hex-→-binary" aria-label="Permalink to &quot;Hex → Binary&quot;">​</a></h3><p>Replace each hex digit with 4 bits.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A      F</span></span>
<span class="line"><span>1010  1111  →  10101111</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h2 id="hex-digit-reference-table" tabindex="-1">Hex Digit Reference Table <a class="header-anchor" href="#hex-digit-reference-table" aria-label="Permalink to &quot;Hex Digit Reference Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dec</th><th>Hex</th><th>Binary</th></tr></thead><tbody><tr><td>0</td><td>0</td><td>0000</td></tr><tr><td>1</td><td>1</td><td>0001</td></tr><tr><td>2</td><td>2</td><td>0010</td></tr><tr><td>3</td><td>3</td><td>0011</td></tr><tr><td>4</td><td>4</td><td>0100</td></tr><tr><td>5</td><td>5</td><td>0101</td></tr><tr><td>6</td><td>6</td><td>0110</td></tr><tr><td>7</td><td>7</td><td>0111</td></tr><tr><td>8</td><td>8</td><td>1000</td></tr><tr><td>9</td><td>9</td><td>1001</td></tr><tr><td>10</td><td>A</td><td>1010</td></tr><tr><td>11</td><td>B</td><td>1011</td></tr><tr><td>12</td><td>C</td><td>1100</td></tr><tr><td>13</td><td>D</td><td>1101</td></tr><tr><td>14</td><td>E</td><td>1110</td></tr><tr><td>15</td><td>F</td><td>1111</td></tr></tbody></table><hr><h2 id="powers-of-2-memorise" tabindex="-1">Powers of 2 (Memorise) <a class="header-anchor" href="#powers-of-2-memorise" aria-label="Permalink to &quot;Powers of 2 (Memorise)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>2⁰</th><th>2¹</th><th>2²</th><th>2³</th><th>2⁴</th><th>2⁵</th><th>2⁶</th><th>2⁷</th><th>2⁸</th><th>2¹⁰</th></tr></thead><tbody><tr><td>1</td><td>2</td><td>4</td><td>8</td><td>16</td><td>32</td><td>64</td><td>128</td><td>256</td><td>1024</td></tr></tbody></table><hr><h2 id="data-sizes-storage" tabindex="-1">Data Sizes (Storage) <a class="header-anchor" href="#data-sizes-storage" aria-label="Permalink to &quot;Data Sizes (Storage)&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>8 bits     = 1 byte</span></span>
<span class="line"><span>1 024 bytes = 1 KB</span></span>
<span class="line"><span>1 024 KB   = 1 MB</span></span>
<span class="line"><span>1 024 MB   = 1 GB</span></span>
<span class="line"><span>1 024 GB   = 1 TB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="storage-calculation-templates" tabindex="-1">Storage Calculation Templates <a class="header-anchor" href="#storage-calculation-templates" aria-label="Permalink to &quot;Storage Calculation Templates&quot;">​</a></h2><p><strong>Text (ASCII — 1 char = 1 byte):</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>characters × 1 byte = bytes → ÷ 1024 for KB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>Image (uncompressed):</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>width × height (pixels) × colour_depth_bits ÷ 8 = bytes → ÷ 1024 → KB → MB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>Audio (uncompressed):</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sample_rate × bit_depth × channels × seconds ÷ 8 = bytes</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="worked-conversion-examples" tabindex="-1">Worked Conversion Examples <a class="header-anchor" href="#worked-conversion-examples" aria-label="Permalink to &quot;Worked Conversion Examples&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Convert</th><th>Working</th><th>Result</th></tr></thead><tbody><tr><td>75₁₀ → binary</td><td>75÷2=37r<strong>1</strong>, 37÷2=18r<strong>1</strong>, 18÷2=9r<strong>0</strong>, 9÷2=4r<strong>1</strong>, 4÷2=2r<strong>0</strong>, 2÷2=1r<strong>0</strong>, 1÷2=0r<strong>1</strong></td><td><strong>1001011</strong></td></tr><tr><td>10011010₂ → decimal</td><td>128+16+8+2</td><td><strong>154</strong></td></tr><tr><td>154₁₀ → hex</td><td>154÷16=9r<strong>10(A)</strong>, 9÷16=0r<strong>9</strong></td><td><strong>9A</strong></td></tr><tr><td>9A₁₆ → decimal</td><td>9×16 + 10×1 = 144+10</td><td><strong>154</strong></td></tr><tr><td>10011010₂ → hex</td><td>group: 1001 1010 = <strong>9 A</strong></td><td><strong>9A</strong></td></tr><tr><td>B3₁₆ → binary</td><td>B=1011, 3=0011</td><td><strong>10110011</strong></td></tr></tbody></table><hr><h2 id="common-ascii-values" tabindex="-1">Common ASCII Values <a class="header-anchor" href="#common-ascii-values" aria-label="Permalink to &quot;Common ASCII Values&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Char</th><th>Dec</th><th>Hex</th></tr></thead><tbody><tr><td>&#39;0&#39;</td><td>48</td><td>30</td></tr><tr><td>&#39;9&#39;</td><td>57</td><td>39</td></tr><tr><td>&#39;A&#39;</td><td>65</td><td>41</td></tr><tr><td>&#39;Z&#39;</td><td>90</td><td>5A</td></tr><tr><td>&#39;a&#39;</td><td>97</td><td>61</td></tr><tr><td>&#39;z&#39;</td><td>122</td><td>7A</td></tr><tr><td>&#39; &#39;</td><td>32</td><td>20</td></tr></tbody></table><p>Key fact: lowercase = uppercase + 32</p>`,52)])])}const u=t(r,[["render",d]]);export{b as __pageData,u as default};
